VALUES
  ('pukao-6f0ba476-moex-00409', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '居住者甲君出租房屋給乙公司，約定租期為109年1月1日至同年12月31日，並於108年12 月23日預收前半年租金共新臺幣60萬元。有關甲君申報綜合所得稅之敘述，下列何者正確？', '["應申報為108年所得", "修繕費用可以「房屋租金支出」申報列舉扣除額減除", "乙公司於給付租金時應協助分離課稅之義務", "甲君可委任乙公司依規定扣繳率申報完稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00410', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '納稅義務人甲君有中華民國戶籍，且一課稅年度內入境居留滿300天，有關甲君綜合所得稅申報， 下列敘述何者錯誤？', '["應就其中華民國來源所得申報繳納稅款", "原則應採合併結算申報", "於中華民國境內提供勞務但由境外雇主給付之報酬新臺幣30萬元應計入所得總額", "取得尾牙摸彩獎金新臺幣2萬元應按20%就源扣繳分離課稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00411', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '有關個人出價取得房地，並適用房地合一稅之敘述，下列何者錯誤？', '["於完成所有權移轉登記日的次日起算30日內完成申報", "若房屋、土地交易結果為虧損可免申報", "應以實際成交價額減除原始取得成本，與因取得、改良及移轉而支付的費用之餘額為所得額", "適用稅率依據持有期間長短而有不同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00412', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '甲公司109年於中華民國境內所得新臺幣500萬元，美國分公司所得折合新臺幣1,000萬元，已 在美國繳納美國分公司所得稅折合新臺幣250萬元，請問甲公司申報繳納我國109年度營利事業 所得稅時可使用國外稅額扣抵上限為多少元？', '["100萬元", "200萬元", "250萬元", "300萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00413', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '甲君過世，死亡時其於婚姻關係存續中取得而現存的原有財產金額為新臺幣 2,000 萬元，甲君配 偶的原有財產則為新臺幣400萬元，請問甲君遺產稅的剩餘財產差額分配請求權上限為？', '["2,000萬元", "1,200萬元", "1,000萬元", "800萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00414', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '甲君於110年2月17日贈與兒子土地及房屋，土地公告現值及房屋評定標準價格合計新臺幣2,220 萬元，110年贈與稅免稅額220萬元，約定由兒子負擔繳納土地增值稅及契稅合計300萬元，請問 贈與稅應納稅額為多少？', '["應納稅額低於贈與之負擔及免稅額，故免稅", "170萬元", "200萬元", "220萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00415', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '假設甲君在連鎖便利商店購買一項售價新臺幣 210元之玩具，該便利商店進貨成本為 160元， 有關營業稅之敘述，下列何者錯誤？', '["統一發票所載售價210元內含營業稅10元", "便利商店進貨時產生進項稅額8元", "營業稅原則為兩個月一期，由便利商店自動報繳", "當期銷項稅額減除進項稅額後如為負數原則可直接退稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00416', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '有關進口貨物課徵營業稅，下列敘述何者正確？', '["納稅義務人為國外生產該貨物之事業、機關、團體、組織", "原則上兩個月為一期，計算該期間進口金額並自行繳納", "進入保稅區之保稅貨物應立即課徵營業稅", "稅基為關稅完稅價格+進口稅+貨物稅或菸酒稅或菸品健康福利捐"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00417', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '甲君在臺北市有一筆土地面積3公畝，107年購入時價格2,000萬元，登記土地所有權人為甲君， 地上有建築物並遷入甲君配偶之戶籍。109年之申報地價1,500萬元，公告現值1,600萬元，臺北 市土地7公畝之平均地價為3,200萬元。有關109年地價稅，下列敘述何者正確？', '["適用稅率為千分之2", "應納地價稅額為32,000元", "納稅義務人為甲君之配偶", "繳納期間為5月1日至5月31日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00418', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '下列那項並非貨物稅課徵標的？', '["水泥", "電冰箱", "汽油", "遊艇"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "ad11cbc4c4d9", "answer_pdf_sha1": "864903e88b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
